311→export async function createOrchestratorSession(
312→  input: CreateSessionInput,
313→): Promise<OrchestratorSessionResult> {
314→  // 0. Intent authorization gate (optional — backwards compatible)
315→  if (input.intentId) {
316→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
317→    if (!gateResult.ok) {
318→      return { ok: false, error: gateResult.error };
319→    }
320→  }
321→
322→  // 1. Validate assignment eligibility
323→  const assignmentResult = await input.validateAssignment(
324→    input.surreal,
325→    input.workspaceId,
326→    input.taskId,
327→  );
328→
329→  if (!assignmentResult.ok) {
330→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
331→  }
332→
333→  const { validation } = assignmentResult;
334→
335→  return createSessionViaAdapter(input, validation);
336→}
