407→// ---------------------------------------------------------------------------
408→// Adapter-based session creation
409→// ---------------------------------------------------------------------------
410→
411→function slugFromTitle(title: string): string {
412→  return title
413→    .toLowerCase()
414→    .replace(/[^a-z0-9]+/g, "-")
415→    .replace(/^-|-$/g, "")
416→    .slice(0, 50);
417→}
418→
419→async function createSessionViaAdapter(
420→  input: CreateSessionInput,
421→  validation: import("./types").AssignmentValidation,
422→): Promise<OrchestratorSessionResult> {
423→  const adapter = input.adapter;
424→  const repoRoot = validation.repoPath;
425→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
426→
427→  // 1. Create worktree for isolated agent work
428→  const worktreeResult = await createWorktree(
429→    input.shellExec,
430→    repoRoot,
431→    taskSlug,
432→  );
433→
434→  if (!worktreeResult.ok) {
435→    return {
436→      ok: false,
437→      error: worktreeError(worktreeResult.error.message),
438→    };
439→  }
440→
441→  const { branchName, worktreePath } = worktreeResult.value;
442→
443→  // 2. Create agent_session record
444→  const { session_id: agentSessionId } = await input.createAgentSession({
445→    surreal: input.surreal,
446→    agent: "claude",
447→    workspaceRecord: validation.workspaceRecord,
448→    taskId: input.taskId,
449→  });
450→
451→  const streamId = generateStreamId(agentSessionId);
452→
453→  // 3. Create session via adapter — agent works in worktree, not main repo
454→  let handle: SessionHandle;
455→  try {
456→    await adapter.setMcpConfig(worktreePath, "brain", {
457→      type: "remote",
458→      url: `${input.brainBaseUrl}/mcp/agent/${agentSessionId}`,
459→      headers: { "X-Brain-Auth": input.mcpAuthToken },
460→    });
461→
462→    handle = await adapter.createSession({
463→      agent: input.sandboxAgentType ?? "claude",
464→      cwd: worktreePath,
465→      ...(input.env ? { env: input.env } : {}),
466→    });
467→  } catch (err) {
468→    // Rollback: remove worktree and delete agent_session on adapter failure
469→    await removeWorktree(input.shellExec, repoRoot, branchName);
470→    const sessionRecord = new RecordId("agent_session", agentSessionId);
471→    await input.surreal.delete(sessionRecord);
472→    return {
473→      ok: false,
474→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
475→    };
476→  }
477→
478→  // 4. Update agent_session with sandbox + worktree fields
479→  const sessionRecord = new RecordId("agent_session", agentSessionId);
480→  await input.surreal.update(sessionRecord).merge({
481→    orchestrator_status: "spawning" as OrchestratorStatus,
482→    stream_id: streamId,
483→    session_type: "sandbox_agent",
484→    provider: "local",
485→    external_session_id: handle.id,
486→    worktree_branch: branchName,
487→    worktree_path: worktreePath,
488→  });
489→
490→  // 5. Transition intent to executing
491→  if (input.intentId) {
492→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
493→  }
494→
495→  return {
496→    ok: true,
497→    value: {
498→      agentSessionId,
499→      streamId,
500→      worktreeBranch: branchName,
501→      sessionHandle: handle,
502→    },
503→  };
504→}
