540→// abortOrchestratorSession
541→// ---------------------------------------------------------------------------
542→
543→type AbortSessionInput = {
544→  surreal: Surreal;
545→  shellExec: ShellExec;
546→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
547→  sessionId: string;
548→  adapter?: SandboxAgentAdapter;
549→  endAgentSession: (input: {
550→    surreal: Surreal;
551→    workspaceRecord: RecordId<"workspace", string>;
552→    sessionId: string;
553→    summary: string;
554→  }) => Promise<{ session_id: string; ended: boolean }>;
555→};
556→
557→export async function abortOrchestratorSession(
558→  input: AbortSessionInput,
559→): Promise<AbortSessionResult> {
560→  const lookup = await lookupSession(input.surreal, input.sessionId);
561→  if (!lookup.ok) {
562→    return { ok: false, error: lookup.error };
563→  }
564→  const { session, record: sessionRecord } = lookup;
565→
566→  // 1. Destroy the sandbox agent session
567→  if (session.external_session_id && input.adapter) {
568→    try {
569→      await input.adapter.destroySession(session.external_session_id);
570→    } catch (err) {
571→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
572→        sessionId: input.sessionId,
573→        externalSessionId: session.external_session_id,
574→        error: String(err),
575→      });
576→    }
577→  }
578→
579→  // 2. Update orchestrator_status to aborted
580→  await input.surreal.update(sessionRecord).merge({
581→    orchestrator_status: "aborted" as OrchestratorStatus,
582→  });
583→
584→  const workspaceRecord = requireWorkspace(session, input.sessionId);
585→
586→  // 3. Remove worktree if branch name exists
587→  if (session.worktree_branch) {
588→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
589→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
590→  }
591→
592→  // 4. Return task to ready
593→  if (session.task_id) {
594→    await input.surreal.update(session.task_id).merge({
595→      status: "ready",
596→      updated_at: new Date(),
597→    });
598→  }
599→
600→  // 5. End the agent session
601→  await input.endAgentSession({
602→    surreal: input.surreal,
603→    workspaceRecord,
604→    sessionId: input.sessionId,
605→    summary: "Session aborted",
606→  });
607→
608→  return {
609→    ok: true,
610→    value: {
611→      aborted: true,
612→      sessionId: input.sessionId,
613→    },
614→  };
615→}
