618→// acceptOrchestratorSession
619→// ---------------------------------------------------------------------------
620→
621→type AcceptSessionInput = {
622→  surreal: Surreal;
623→  shellExec: ShellExec;
624→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
625→  sessionId: string;
626→  summary: string;
627→  adapter?: SandboxAgentAdapter;
628→  endAgentSession: (input: {
629→    surreal: Surreal;
630→    workspaceRecord: RecordId<"workspace", string>;
631→    sessionId: string;
632→    summary: string;
633→  }) => Promise<{ session_id: string; ended: boolean }>;
634→};
635→
636→export async function acceptOrchestratorSession(
637→  input: AcceptSessionInput,
638→): Promise<AcceptSessionResult> {
639→  const lookup = await lookupSession(input.surreal, input.sessionId);
640→  if (!lookup.ok) {
641→    return { ok: false, error: lookup.error };
642→  }
643→  const { session, record: sessionRecord, status } = lookup;
644→
645→  if (!ACCEPTABLE_STATUSES.has(status)) {
646→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
647→  }
648→
649→  const workspaceRecord = requireWorkspace(session, input.sessionId);
650→
651→  // 1. Destroy the sandbox agent session
652→  if (session.external_session_id && input.adapter) {
653→    try {
654→      await input.adapter.destroySession(session.external_session_id);
655→    } catch (err) {
656→      log.warn("orchestrator.accept", "Failed to destroy sandbox session", {
657→        sessionId: input.sessionId,
658→        externalSessionId: session.external_session_id,
659→        error: String(err),
660→      });
661→    }
662→  }
663→
664→  // 2. Update orchestrator_status to completed
665→  await input.surreal.update(sessionRecord).merge({
666→    orchestrator_status: "completed" as OrchestratorStatus,
667→  });
668→
669→  // 3. Remove worktree (branch is preserved for merge/review)
670→  if (session.worktree_branch) {
671→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
672→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
673→  }
674→
675→  // 4. End the agent session
676→  await input.endAgentSession({
677→    surreal: input.surreal,
678→    workspaceRecord,
679→    sessionId: input.sessionId,
680→    summary: input.summary,
681→  });
682→
683→  return {
684→    ok: true,
685→    value: {
686→      accepted: true,
687→      sessionId: input.sessionId,
688→    },
689→  };
690→}
