692→// ---------------------------------------------------------------------------
693→// State guard helpers
694→// ---------------------------------------------------------------------------
695→
696→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
697→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
698→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
699→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
700→
701→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
702→  return {
703→    code: "SESSION_ERROR",
704→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
705→    httpStatus: 409,
706→  };
707→}
708→
709→function sessionAborted(sessionId: string): SessionError {
710→  return {
711→    code: "SESSION_ERROR",
712→    message: `Session ${sessionId} has been aborted`,
713→    httpStatus: 409,
714→  };
715→}
716→
717→// ---------------------------------------------------------------------------
718→// getOrchestratorReview
719→// ---------------------------------------------------------------------------
720→
721→type GetReviewInput = {
722→  surreal: Surreal;
723→  sessionId: string;
724→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
725→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
726→  getTaskTitle: (taskId: string) => Promise<string>;
727→};
728→
729→export async function getOrchestratorReview(
730→  input: GetReviewInput,
731→): Promise<ReviewResult> {
732→  const lookup = await lookupSession(input.surreal, input.sessionId);
733→  if (!lookup.ok) {
734→    return { ok: false, error: lookup.error };
735→  }
736→  const { session, status } = lookup;
737→
738→  if (status === "aborted") {
739→    return { ok: false, error: sessionAborted(input.sessionId) };
740→  }
741→
742→  if (!REVIEWABLE_STATUSES.has(status)) {
743→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
744→  }
745→
746→  // Get diff from the branch
747→  const branchName = session.worktree_branch ?? "";
748→  const workspaceRecord = requireWorkspace(session, input.sessionId);
749→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
750→  const diffResult = await input.getDiff(repoRoot, branchName);
751→
752→  const diff = diffResult.ok
753→    ? diffResult.value
754→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
755→
756→  // Get task title
757→  const taskId = session.task_id ? session.task_id.id : "";
758→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
759→
760→  return {
761→    ok: true,
762→    value: {
763→      taskTitle,
764→      diff,
765→      session: {
766→        orchestratorStatus: status,
767→        ...pickDefined({
768→          worktreeBranch: session.worktree_branch,
769→          startedAt: session.started_at,
770→          lastEventAt: session.last_event_at,
771→        }),
772→      },
773→    },
774→  };
775→}
776→
777→// ---------------------------------------------------------------------------
778→// rejectOrchestratorSession
779→// ---------------------------------------------------------------------------
780→
781→type RejectSessionInput = {
782→  surreal: Surreal;
783→  sessionId: string;
784→  feedback: string;
785→};
786→
787→export async function rejectOrchestratorSession(
788→  input: RejectSessionInput,
789→): Promise<RejectSessionResult> {
790→  const lookup = await lookupSession(input.surreal, input.sessionId);
791→  if (!lookup.ok) {
792→    return { ok: false, error: lookup.error };
793→  }
794→  const { session, record: sessionRecord, status } = lookup;
795→
796→  if (!REJECTABLE_STATUSES.has(status)) {
797→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
798→  }
799→
800→  // 1. Update session status to active (agent resumes work)
801→  await input.surreal.update(sessionRecord).merge({
802→    orchestrator_status: "active" as OrchestratorStatus,
803→    last_feedback: input.feedback,
804→  });
805→
806→  // 2. Return task to in_progress
807→  if (session.task_id) {
808→    await input.surreal.update(session.task_id).merge({
809→      status: "in_progress",
810→      updated_at: new Date(),
811→    });
812→  }
813→
814→  return {
815→    ok: true,
816→    value: {
817→      rejected: true,
818→      continuing: true,
819→    },
820→  };
821→}
822→
823→// ---------------------------------------------------------------------------
824→// sendSessionPrompt
825→// ---------------------------------------------------------------------------
826→
827→type SendPromptInput = {
828→  surreal: Surreal;
829→  sessionId: string;
830→  text: string;
831→  adapter: SandboxAgentAdapter;
832→};
833→
834→export async function sendSessionPrompt(
835→  input: SendPromptInput,
836→): Promise<PromptSessionResult> {
837→  const lookup = await lookupSession(input.surreal, input.sessionId);
838→  if (!lookup.ok) {
839→    return { ok: false, error: lookup.error };
840→  }
841→  const { session, status } = lookup;
842→
843→  if (!PROMPTABLE_STATUSES.has(status)) {
844→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
845→    if (TERMINAL_STATUSES.has(status)) {
846→      return { ok: false, error: sessionNotFound(input.sessionId) };
847→    }
848→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
849→  }
850→
851→  if (!session.external_session_id) {
852→    return {
853→      ok: false,
854→      error: {
855→        code: "SESSION_ERROR",
856→        message: `Session ${input.sessionId} has no external_session_id — cannot deliver prompt`,
857→        httpStatus: 500,
858→      },
859→    };
860→  }
861→
862→  try {
863→    const handle = await input.adapter.resumeSession(session.external_session_id);
864→    await handle.prompt([{ type: "text", text: input.text }]);
865→    return { ok: true, value: { delivered: true } };
866→  } catch (err) {
867→    return {
868→      ok: false,
869→      error: {
870→        code: "SESSION_ERROR",
871→        message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
872→        httpStatus: 500,
873→      },
874→    };
875→  }
876→}
