 70→
 71→export type OrchestratorRouteDeps = {
 72→  createSession: (
 73→    workspaceId: string,
 74→    taskId: string,
 75→    authToken: string,
 76→  ) => Promise<OrchestratorSessionResult>;
 77→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 78→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 79→  acceptSession: (
 80→    sessionId: string,
 81→    summary: string,
 82→  ) => Promise<AcceptSessionResult>;
 83→  getReview: (sessionId: string) => Promise<ReviewResult>;
 84→  rejectSession: (
 85→    sessionId: string,
 86→    feedback: string,
 87→  ) => Promise<RejectSessionResult>;
 88→  sendPrompt: (
 89→    sessionId: string,
 90→    text: string,
 91→  ) => Promise<PromptSessionResult>;
