 94→// ---------------------------------------------------------------------------
 95→// Request body parsing
 96→// ---------------------------------------------------------------------------
 97→
 98→type AssignBody = { taskId?: string };
 99→type AcceptBody = { summary?: string };
100→type RejectBody = { feedback?: string };
101→type PromptBody = { text?: string };
102→
103→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
104→  try {
105→    return (await request.json()) as T;
106→  } catch {
107→    return undefined;
108→  }
109→}
110→
111→function extractAuthToken(request: Request): string {
112→  return request.headers.get("Cookie") ?? "";
113→}
114→
115→// ---------------------------------------------------------------------------
116→// Response builders (pure)
117→// ---------------------------------------------------------------------------
118→
119→function assignResponse(
120→  workspaceId: string,
121→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
122→): Response {
123→  return jsonResponse(
124→    {
125→      agentSessionId: value.agentSessionId,
126→      streamId: value.streamId,
127→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
128→    },
129→    200,
130→  );
131→}
132→
133→function statusResponse(
134→  sessionId: string,
135→  value: {
136→    orchestratorStatus: string;
137→    worktreeBranch?: string;
138→    worktreePath?: string;
139→    startedAt?: string;
140→    lastEventAt?: string;
141→    error?: string;
142→  },
143→): Response {
144→  return jsonResponse(
145→    {
146→      agentSessionId: sessionId,
147→      orchestratorStatus: value.orchestratorStatus,
148→      ...pickDefined({
149→        worktreeBranch: value.worktreeBranch,
150→        worktreePath: value.worktreePath,
151→        startedAt: value.startedAt,
152→        lastEventAt: value.lastEventAt,
153→        error: value.error,
154→      }),
155→    },
156→    200,
157→  );
158→}
159→
160→function acceptResponse(): Response {
161→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
162→}
163→
164→function abortResponse(): Response {
165→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
166→}
167→
168→function reviewResponse(value: {
169→  taskTitle: string;
170→  diff: unknown;
171→  session: unknown;
172→}): Response {
173→  return jsonResponse(value, 200);
174→}
175→
176→function rejectResponse(): Response {
177→  return jsonResponse({ rejected: true, continuing: true }, 200);
178→}
179→
180→function promptResponse(): Response {
181→  return jsonResponse({ delivered: true }, 202);
182→}
183→
184→function sessionErrorResponse(error: {
185→  message: string;
186→  httpStatus: number;
187→}): Response {
188→  return jsonError(error.message, error.httpStatus);
189→}
