191→// ---------------------------------------------------------------------------
192→// Route handler factory
193→// ---------------------------------------------------------------------------
194→
195→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
196→  const assign: RouteHandler = async (request) => {
197→    const workspaceId = request.params.workspaceId;
198→    const body = await parseJsonBody<AssignBody>(request);
199→
200→    if (!body?.taskId) {
201→      return jsonError("taskId is required", 400);
202→    }
203→
204→    const authToken = extractAuthToken(request);
205→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
206→
207→    if (!result.ok) {
208→      return sessionErrorResponse(result.error);
209→    }
210→
211→    return assignResponse(workspaceId, result.value);
212→  };
213→
214→  const status: RouteHandler = async (request) => {
215→    const sessionId = request.params.sessionId;
216→    const result = await deps.getSessionStatus(sessionId);
217→
218→    if (!result.ok) {
219→      return sessionErrorResponse(result.error);
220→    }
221→
222→    return statusResponse(sessionId, result.value);
223→  };
224→
225→  const accept: RouteHandler = async (request) => {
226→    const sessionId = request.params.sessionId;
227→    const body = await parseJsonBody<AcceptBody>(request);
228→    const summary = body?.summary ?? "";
229→
230→    const result = await deps.acceptSession(sessionId, summary);
231→
232→    if (!result.ok) {
233→      return sessionErrorResponse(result.error);
234→    }
235→
236→    return acceptResponse();
237→  };
238→
239→  const abort: RouteHandler = async (request) => {
240→    const sessionId = request.params.sessionId;
241→    const result = await deps.abortSession(sessionId);
242→
243→    if (!result.ok) {
244→      return sessionErrorResponse(result.error);
245→    }
246→
247→    return abortResponse();
248→  };
249→
250→  const review: RouteHandler = async (request) => {
251→    const sessionId = request.params.sessionId;
252→    const result = await deps.getReview(sessionId);
253→
254→    if (!result.ok) {
255→      return sessionErrorResponse(result.error);
256→    }
257→
258→    return reviewResponse(result.value);
259→  };
260→
261→  const reject: RouteHandler = async (request) => {
262→    const sessionId = request.params.sessionId;
263→    const body = await parseJsonBody<RejectBody>(request);
264→
265→    if (!body?.feedback || body.feedback.trim() === "") {
266→      return jsonError("feedback is required", 400);
267→    }
268→
269→    const result = await deps.rejectSession(sessionId, body.feedback);
270→
271→    if (!result.ok) {
272→      return sessionErrorResponse(result.error);
273→    }
274→
275→    return rejectResponse();
276→  };
277→
278→  const prompt: RouteHandler = async (request) => {
279→    const sessionId = request.params.sessionId;
280→    const body = await parseJsonBody<PromptBody>(request);
281→
282→    if (!body?.text || body.text.trim() === "") {
283→      return jsonError("text is required", 400);
284→    }
285→
286→    const result = await deps.sendPrompt(sessionId, body.text);
287→
288→    if (!result.ok) {
289→      return sessionErrorResponse(result.error);
290→    }
291→
292→    return promptResponse();
293→  };
294→
295→  return { assign, status, accept, abort, review, reject, prompt };
296→}
