### SKILL.md generator

```typescript
function generateSkillMd(skill: {
  id: string;
  name: string;
  description: string;
  version: string;
  content: string;
  requiredTools: Array<{ name: string }>;
  workspaceId: string;
}): string {
  const allowedTools = skill.requiredTools.map(t => t.name).join(" ");
  const frontmatter = [
    "---",
    `name: ${skill.name}`,
    `description: ${skill.description}`,
    ...(allowedTools ? [`allowed-tools: ${allowedTools}`] : []),
    "metadata:",
    `  brain-skill-id: ${skill.id}`,
    `  brain-version: ${skill.version}`,
    `  brain-workspace: ${skill.workspaceId}`,
    "---",
  ].join("\n");

  return `${frontmatter}\n\n${skill.content}\n`;
}
```

